% ============================================================
% POLICY RULES (executable Prolog sketches)
% ============================================================

% Cover suspension rule
cover_suspended(Policy, At) :-
    cover_suspension(Policy, Start, End),
    not_before(At, Start),
    not_after(At, End).

% Deductible application
net_claim(Source, Net) :-
    hm_claim_total(Source, Gross),
    hm_claim_deductible(_, Ded),
    Net is Gross - Ded.

% Reinsurance trigger check
reinsurance_triggered(Treaty, no) :-
    reinsurance_share(Reassured, Share, NetClaim, ReassuredShare),
    reinsurance_attachment(Treaty, Attachment),
    ReassuredShare < Attachment.

% Reinsurance notice compliance
reinsurance_notice_compliant(Treaty, no) :-
    reinsurance_notice_elapsed_hours(Treaty, Elapsed),
    reinsurance_notice_hours(Treaty, Required),
    Elapsed > Required.

% Regulatory deadline compliance
regulatory_deadline_met(Directive, yes) :-
    regulatory_directive_deadline(Directive, MaxHours, hours),
    regulatory_compliance_elapsed(Directive, ActualHours, hours),
    ActualHours =< MaxHours.
